description:
Modify renode/peripherals/SX1262.cs to send RX_ENTER when firmware issues SetRx.

SetRx opcode is 0x82, followed by 3 bytes for timeout (24-bit, 15.625us steps).

```csharp
private void HandleSetRx(byte[] args)
{
    // Parse timeout: 3 bytes, 15.625us per step
    uint timeoutSteps = (uint)(args[0] << 16 | args[1] << 8 | args[2]);
    uint timeoutUs = timeoutSteps * 15625 / 1000;  // convert to microseconds

    // Special case: 0xFFFFFF = continuous RX (no timeout)
    if (timeoutSteps == 0xFFFFFF)
        timeoutUs = 0xFFFFFFFF;  // max uint = "infinite"

    rxMode = true;

    // Send RX_ENTER to simulation
    SendToSim(EncodeRxEnter(timeoutUs));

    this.Log(LogLevel.Debug, "SetRx: timeout {0} us", timeoutUs);
}

private byte[] EncodeRxEnter(uint timeoutUs)
{
    // MSG_RX_ENTER (0x24) + 4-byte LE timeout
    var msg = new byte[5];
    msg[0] = 0x24;
    msg[1] = (byte)(timeoutUs & 0xFF);
    msg[2] = (byte)((timeoutUs >> 8) & 0xFF);
    msg[3] = (byte)((timeoutUs >> 16) & 0xFF);
    msg[4] = (byte)((timeoutUs >> 24) & 0xFF);
    return msg;
}
```

Note: SetRx is already partially handled (sets internal state). This adds the sim notification.
